import React from 'react';
import PropTypes from 'prop-types';
import { useTheme } from '../../contexts/ThemeContext';
import TextAnimation from '../common/TextAnimation';
import styles from './About.module.css';

/**
 * About component displaying personal and professional information
 * @param {Object} props - Component props
 * @param {Object} props.data - About section data
 * @param {string} props.data.name - Full name
 * @param {string} props.data.title - Professional title
 * @param {string} props.data.summary - Short bio summary
 * @param {string} props.data.description - Longer description about skills and experience
 * @param {Array} props.data.highlights - List of key highlights or interesting facts
 * @param {string} props.className - Additional CSS class name
 * @returns {JSX.Element} Rendered About component
 */
const About = ({ data = {}, className = '' }) => {
  const { theme } = useTheme();
  const { name, title, summary, description, highlights = [] } = data;

  return (
    <section 
      className={`${styles.about} ${className}`} 
      data-testid="about-section"
      data-theme={theme}
    >
      <div className={styles.container}>
        <TextAnimation 
          element="h2" 
          text="About Me" 
          animation="fadeInUp" 
          className={styles.sectionTitle}
          delay={100}
        />
        
        {name && (
          <TextAnimation 
            element="h3" 
            text={name} 
            animation="fadeInUp"
            className={styles.name}
            delay={200}
          />
        )}
        
        {title && (
          <TextAnimation 
            element="h4" 
            text={title} 
            animation="fadeInUp"
            className={styles.title}
            delay={300}
          />
        )}
        
        {summary && (
          <TextAnimation 
            element="p" 
            text={summary} 
            animation="fadeInUp"
            className={styles.summary}
            delay={400}
          />
        )}
        
        {description && (
          <TextAnimation 
            element="div" 
            animation="fadeInUp"
            className={styles.description}
            delay={500}
          >
            {description.split('\n').map((paragraph, index) => (
              <p key={index}>{paragraph}</p>
            ))}
          </TextAnimation>
        )}
        
        {highlights && highlights.length > 0 && (
          <div className={styles.highlights}>
            <TextAnimation 
              element="h4" 
              text="Highlights" 
              animation="fadeInUp"
              delay={600}
            />
            <ul className={styles.highlightsList}>
              {highlights.map((highlight, index) => (
                <TextAnimation 
                  key={index}
                  element="li" 
                  text={highlight} 
                  animation="fadeInUp"
                  delay={700 + (index * 100)}
                  className={styles.highlightItem}
                />
              ))}
            </ul>
          </div>
        )}
      </div>
    </section>
  );
};

About.propTypes = {
  data: PropTypes.shape({
    name: PropTypes.string,
    title: PropTypes.string,
    summary: PropTypes.string,
    description: PropTypes.string,
    highlights: PropTypes.arrayOf(PropTypes.string)
  }),
  className: PropTypes.string
};

export default About;
